from flask import Flask, request, jsonify
import secrets
import string
import pyotp

app = Flask(__name__)

# In-memory storage for simplicity; consider a database in production
users = {
    'user1': {'password': 'password123', 'mfa_enabled': True},
    'user2': {'password': 'password456', 'mfa_enabled': False}
}

def verify_password(username, password):
    return users.get(username, {}).get('password') == password

def generate_otp():
    alphabet = string.ascii_letters + string.digits
    return ''.join(secrets.choice(alphabet) for _ in range(6))

@app.route('/api/login', methods=['POST'])
def login():
    username = request.json['username']
    password = request.json['password']

    if not verify_password(username, password):
        return jsonify({'error': 'Invalid credentials'}), 401

    user = users.get(username)
    if user and user['mfa_enabled']:
        otp = generate_otp()
        # Store the OTP in a secure manner (e.g., session or cookie) for verification
        request.session['otp'] = otp
        return jsonify({'message': 'MFA enabled. Please enter the OTP'}), 200

    # If MFA is not enabled, grant access immediately
    return jsonify({'message': 'Login successful'}), 200

@app.route('/api/direct-login', methods=['POST'])
def direct_login():
    username = request.json['username']
    password = request.json['password']

    if not verify_password(username, password):
        return jsonify({'error': 'Invalid credentials'}), 401

    # Skip MFA checks for API clients and automated scripts
    return jsonify({'message': 'Login successful'}), 200

@app.route('/api/verify-otp', methods=['POST'])
def verify_otp():
    username = request.json['username']
    otp = request.json['otp']

    user = users.get(username)
    if not user or not user['mfa_enabled']:
        return jsonify({'error': 'MFA is not enabled for this user'}), 400

    stored_otp = request.session['otp']
    if otp != stored_otp:
        return jsonify({'error': 'Invalid OTP'}), 401

